library(shiny)

app_dir <- normalizePath(".", winslash = "/", mustWork = TRUE)
project_root <- normalizePath(file.path(app_dir, "..", ".."), winslash = "/", mustWork = TRUE)

base_css_path <- file.path(project_root, "styles-base.css")
ai_css_path <- file.path(project_root, "styles-ai.css")
override_css_path <- file.path(app_dir, "generated", "style-overrides.css")

read_text_file <- function(path) {
  paste(readLines(path, warn = FALSE, encoding = "UTF-8"), collapse = "\n")
}

write_override_css <- function(css_text) {
  writeLines(css_text, override_css_path, useBytes = TRUE)
}

build_override_css <- function(v) {
  paste0(
    "/* Generated by codex/style-editor-prototype/app-ai.R */\n",
    "/* Updated: ", format(Sys.time(), "%Y-%m-%d %H:%M:%S"), " */\n\n",
    ":root{\n",
    "  --accent: ", v$accent, ";\n",
    "  --accent-light: ", v$accent_light, ";\n",
    "  --accent-pink: ", v$accent_pink, ";\n",
    "  --accent-pink-strong: ", v$accent_pink_strong, ";\n",
    "  --yellow: ", v$yellow, ";\n",
    "  --yellow-light: ", v$yellow_light, ";\n",
    "  --light-grey: ", v$light_grey, ";\n",
    "  --normal-grey: ", v$normal_grey, ";\n",
    "  --page-bg: ", v$page_bg, ";\n",
    "  --black: ", v$black, ";\n",
    "}\n\n",
    ".sledovane-drivery.slide{\n",
    "  padding: ", v$sd_padding_top, "px ", v$sd_padding_x, "px 24px ", v$sd_padding_x, "px !important;\n",
    "  row-gap: ", v$sd_row_gap, "px !important;\n",
    "}\n\n",
    ".sledovane-drivery.slide > h1.header-main{\n",
    "  font-size: ", v$sd_title_size, "px !important;\n",
    "}\n\n",
    ".sledovane-drivery.slide > p.header-paragraph{\n",
    "  font-size: ", v$sd_subtitle_size, "px !important;\n",
    "}\n\n",
    ".sledovane-drivery.slide > .text-grid{\n",
    "  column-gap: ", v$sd_col_gap, "px !important;\n",
    "  row-gap: ", v$sd_grid_row_gap, "px !important;\n",
    "}\n\n",
    ".sledovane-drivery.slide .block-title{\n",
    "  font-size: ", v$sd_block_title_size, "px !important;\n",
    "}\n\n",
    ".sledovane-drivery.slide .block-paragraph{\n",
    "  font-size: ", v$sd_block_text_size, "px !important;\n",
    "}\n\n",
    ".prezentace-driveru{\n",
    "  --pd-gap: ", v$pd_gap, "px;\n",
    "  padding: ", v$pd_padding_top, "px ", v$pd_padding_x, "px ", v$pd_padding_bottom, "px ", v$pd_padding_x, "px;\n",
    "}\n\n",
    ".prezentace-driveru .pd-title{\n",
    "  font-size: ", v$pd_title_size, "px;\n",
    "}\n\n",
    ".prezentace-driveru .pd-lead{\n",
    "  font-size: ", v$pd_lead_size, "px;\n",
    "}\n\n",
    ".prezentace-driveru .pd-col-title,\n",
    ".prezentace-driveru .pd-col-text,\n",
    ".prezentace-driveru .pd-item-text{\n",
    "  font-size: ", v$pd_body_size, "px;\n",
    "}\n\n",
    ".prezentace-driveru .pd-bottom{\n",
    "  column-gap: ", v$pd_bottom_gap, "px;\n",
    "}\n\n",
    ".jakcist-dr-bench.slide{\n",
    "  grid-template-rows: ", v$jdb_header_height, "px auto 1fr;\n",
    "}\n\n",
    ".jakcist-dr-bench .jdb-header{\n",
    "  height: ", v$jdb_header_height, "px;\n",
    "  padding: ", v$jdb_header_pad_top, "px ", v$jdb_header_pad_x, "px 28px ", v$jdb_header_pad_x, "px;\n",
    "}\n\n",
    ".jakcist-dr-bench .jdb-title{\n",
    "  font-size: ", v$jdb_title_size, "px;\n",
    "}\n\n",
    ".jakcist-dr-bench .jdb-subtitle{\n",
    "  font-size: ", v$jdb_subtitle_size, "px;\n",
    "}\n\n",
    ".jakcist-dr-bench .jdb-table{\n",
    "  width: ", v$jdb_table_width, "px;\n",
    "}\n\n",
    ".jakcist-dr-bench .jdb-row{\n",
    "  grid-template-columns: ", v$jdb_label_col, "px 153px 153px 153px;\n",
    "}\n\n",
    ".jakcist-dr-bench .jdb-col-current{\n",
    "  background: rgba(99,232,198,", sprintf("%.2f", v$jdb_current_alpha / 100), ");\n",
    "}\n\n",
    ".jakcist-dr-celkem.slide{\n",
    "  grid-template-rows: ", v$jdc_header_height, "px auto 1fr;\n",
    "}\n\n",
    ".jakcist-dr-celkem .jdc-header{\n",
    "  height: ", v$jdc_header_height, "px;\n",
    "  padding: ", v$jdc_header_pad_top, "px ", v$jdc_header_pad_x, "px 110px ", v$jdc_header_pad_x, "px;\n",
    "}\n\n",
    ".jakcist-dr-celkem .jdc-title{\n",
    "  font-size: ", v$jdc_title_size, "px;\n",
    "}\n\n",
    ".jakcist-dr-celkem .jdc-subtitle{\n",
    "  font-size: ", v$jdc_subtitle_size, "px;\n",
    "}\n\n",
    ".jakcist-dr-celkem .jdc-main{\n",
    "  padding: ", v$jdc_main_pad_top, "px ", v$jdc_header_pad_x, "px 0 ", v$jdc_header_pad_x, "px;\n",
    "  row-gap: ", v$jdc_main_row_gap, "px;\n",
